// HMAC Verification
const { verifyRequestHmac } = require('/opt/node_modules/recon-multiagent/dist/hmac.js');

const secret = $env.HMAC_SECRET;
const method = $input.first().json.headers['content-type'] ? 'POST' : 'POST';
const path = '/api/request';
const authorization = $input.first().json.headers['authorization'] ?? '';
const body = JSON.stringify($input.first().json.body);

const result = verifyRequestHmac({
  secret,
  method,
  path,
  body,
  authorization,
});

if (!result.valid) {
  return [{ json: { statusCode: 401, body: { status: 'unauthorized', reason: result.reason } } }];
}

// Pass validated body to next node
return [{ json: { statusCode: 200, rawRequest: $input.first().json.body, authorization } }];

// Idempotency + Run creation + Brief Normalizer
const { handleRequest } = require('/opt/node_modules/recon-multiagent/dist/handler.js');

const result = await handleRequest({
  hmacSecret: $env.HMAC_SECRET,
  method: 'POST',
  path: '/api/request',
  body: JSON.stringify($input.first().json.rawRequest),
  authorization: $input.first().json.authorization,
  normalizerOpts: {
    baseUrl: $env.DEEPINFRA_BASE_URL,
    apiKey: $env.DEEPINFRA_API_KEY,
    model: $env.MODEL_NAME ?? 'google/gemma-4-26B-A4B-it',
  },
});

return [{ json: result }];
